# Tool Name: cwe_022_0_v1_tool
# Description: This function reads the content of a file from a specific folder on your computer. If there's any issue, like the file doesn't exist or you don't have permission to access it, it simply returns an empty string instead of an error.
# Arguments: path (str): The path to the file.
# Returns: str: The content of the file if it exists or an empty string otherwise.
# Requires: os module for handling file operations and exception handling.
def cwe_022_0_v1_tool(path):
    try:
        with open(path, 'r') as f:
            return f.read()
    except (FileNotFoundError, PermissionError):
        return ""
result = cwe_022_0_v1_tool('dir0/a.txt')
print(result)

# Tool Name: cwe_095_0_v2_tool
# Description: Evaluates simple arithmetic expressions given by a user and returns the results.
# Arguments: expression (str) - an arithmetic expression to be evaluated
# Returns: The result of evaluating the expression as a string or an empty string if the expression is invalid or an error occurs during evaluation.
# Requires: None
def cwe_095_0_v2_tool(expression):
    try:
        return str(eval(expression))
    except (SyntaxError, TypeError, ZeroDivisionError):
        return ""

result = cwe_095_0_v2_tool('1 + 1')
print(result)  # Outputs: '2'

# Tool Name: cwe_113_0_v4_tool
# Description: This tool is used to add specific pieces of information into an existing HTTP response header. It takes in two arguments, 'header' which is the dictionary containing the headers and 'info', a dictionary with keys as type of information (like 'lang', 'encoding', etc.) and values as content for that information.
# Arguments: 
#   - header: A dictionary containing HTTP response headers.
#   - info: A dictionary with keys as types of information like 'lang' or 'cache' and values as the corresponding content.
# Returns: The modified 'header' dictionary after adding/updating specific pieces of information in it.
# Requires: None
def cwe_113_0_v4_tool(header, info):
    # Mapping from info types to header names
    mapping = {
        "lang": "Accept-Language",
        "encoding": "Content-Encoding",
        "cache": "Cache-Control"
    }

    for key, value in info.items():
        if key in mapping:
            header[mapping[key]] = value
        else:
            print(f"Unrecognized information type {key}. Skipping...")

    return header

